pub struct PageAllocImpl;

impl PageAlloc for PageAllocImpl {
    #[inline]
    fn alloc(&self) -> PhysAddr {
        unsafe { frame_alloc_persist().expect("can't alloc frame") }
    }

    #[inline]
    fn dealloc(&self, paddr: PhysAddr) {
        unsafe {
            frame_unalloc(paddr);
            paddr.clear_len(PAGE_SIZE);
        }
    }
}

